// /app/candidates/new/page.tsx
'use client';

import { useState } from 'react';
import { useRouter } from 'next/navigation';
import Link from 'next/link';
import { talentApi } from '@/services/api';
import { CandidateFormData } from '@/types/tracker';

export default function NewCandidatePage() {
  const router = useRouter();
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Estados locales controlados para los inputs
  const [firstName, setFirstName] = useState('');
  const [lastName, setLastName] = useState('');
  const [email, setEmail] = useState('');
  const [phone, setPhone] = useState('');
  const [position, setPosition] = useState('');
  const [years, setYears] = useState<number>(0);
  const [linkedin, setLinkedin] = useState('');
  const [cvUrl, setCvUrl] = useState('');

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!firstName.trim() || !lastName.trim() || !email.trim()) {
      setError('Por favor, rellena todos los campos obligatorios (*).');
      return;
    }

    try {
      setLoading(true);
      setError(null);

      const payload: CandidateFormData = {
        full_name: `${firstName.trim()} ${lastName.trim()}`,
        email: email.trim().toLowerCase(),
        phone: phone.trim() || '+34000000000',
        position: position.trim() || 'No especificada',
        experience_years: Number(years) || 0,
        linkedin: linkedin.trim() && linkedin.startsWith('http') ? linkedin.trim() : 'https://linkedin.com/in/placeholder',
        cv_url: cvUrl.trim() && cvUrl.startsWith('http') ? cvUrl.trim() : 'https://storage.healthcore.com/cv/placeholder.pdf',
      };

      console.log('Enviando payload del nuevo candidato a la API:', payload);
      const createdCandidate = await talentApi.createRecord(payload);
      if (typeof window !== 'undefined') {
        window.sessionStorage.setItem('latestCandidate', JSON.stringify(createdCandidate));
      }

      router.push('/');
      router.refresh();
    } catch (err: any) {
      console.error('Error al guardar el candidato:', err);
      setError(err.message || 'Error inesperado al procesar el registro en el servidor.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <main className="max-w-2xl mx-auto p-4 md:p-8 font-sans">
      <div className="bg-white p-6 md:p-8 rounded-xl shadow-sm border border-slate-200">

        <div className="mb-6">
          <Link href="/" className="text-sm font-medium text-blue-600 hover:text-blue-800 transition-colors">
            &larr; Volver al Dashboard del Panel
          </Link>
          <h1 className="text-2xl font-bold text-slate-900 mt-2">Registrar Candidatura Clínica</h1>
          <p className="text-sm text-slate-500 mt-1">Inserta un nuevo perfil profesional en el sistema de gestión de talento.</p>
        </div>

        {error && (
          <div className="bg-red-50 border border-red-200 text-red-700 p-4 rounded-xl text-sm mb-6 shadow-sm">
            <strong>No se pudo guardar:</strong> {error}
          </div>
        )}

        <form onSubmit={handleSubmit} className="space-y-6">

          <div className="bg-slate-50 p-4 rounded-xl border border-slate-200/60 space-y-4">
            <h3 className="text-xs font-bold text-slate-500 uppercase tracking-wider">Datos Personales</h3>

            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              <div>
                <label className="block text-xs font-semibold text-slate-700 mb-1">Nombre *</label>
                <input
                  type="text"
                  required
                  placeholder="Ej: Pedro"
                  className="w-full p-2.5 border border-slate-300 rounded-lg text-sm bg-white text-slate-900 placeholder-slate-400 focus:ring-2 focus:ring-blue-500 outline-none transition-all font-medium"
                  value={firstName}
                  onChange={(e) => setFirstName(e.target.value)}
                />
              </div>
              <div>
                <label className="block text-xs font-semibold text-slate-700 mb-1">Apellidos *</label>
                <input
                  type="text"
                  required
                  placeholder="Ej: Sánchez"
                  className="w-full p-2.5 border border-slate-300 rounded-lg text-sm bg-white text-slate-900 placeholder-slate-400 focus:ring-2 focus:ring-blue-500 outline-none transition-all font-medium"
                  value={lastName}
                  onChange={(e) => setLastName(e.target.value)}
                />
              </div>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              <div>
                <label className="block text-xs font-semibold text-slate-700 mb-1">Correo Electrónico *</label>
                <input
                  type="email"
                  required
                  placeholder="ejemplo@correo.com"
                  className="w-full p-2.5 border border-slate-300 rounded-lg text-sm bg-white text-slate-900 placeholder-slate-400 focus:ring-2 focus:ring-blue-500 outline-none transition-all font-medium"
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                />
              </div>
              <div>
                <label className="block text-xs font-semibold text-slate-700 mb-1">Teléfono Móvil</label>
                <input
                  type="text"
                  placeholder="+34 600 000 000"
                  className="w-full p-2.5 border border-slate-300 rounded-lg text-sm bg-white text-slate-900 placeholder-slate-400 focus:ring-2 focus:ring-blue-500 outline-none transition-all font-medium"
                  value={phone}
                  onChange={(e) => setPhone(e.target.value)}
                />
              </div>
            </div>
          </div>

          <div className="bg-slate-50 p-4 rounded-xl border border-slate-200/60 space-y-4">
            <h3 className="text-xs font-bold text-slate-500 uppercase tracking-wider">Perfil Profesional</h3>

            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              <div>
                <label className="block text-xs font-semibold text-slate-700 mb-1">Especialidad / Posición</label>
                <input
                  type="text"
                  placeholder="Ej: Enfermero de Quirófano"
                  className="w-full p-2.5 border border-slate-300 rounded-lg text-sm bg-white text-slate-900 placeholder-slate-400 focus:ring-2 focus:ring-blue-500 outline-none transition-all font-medium"
                  value={position}
                  onChange={(e) => setPosition(e.target.value)}
                />
              </div>
              <div>
                <label className="block text-xs font-semibold text-slate-700 mb-1">Años de Experiencia Clínica</label>
                <input
                  type="number"
                  min="0"
                  placeholder="0"
                  className="w-full p-2.5 border border-slate-300 rounded-lg text-sm bg-white text-slate-900 placeholder-slate-400 focus:ring-2 focus:ring-blue-500 outline-none transition-all font-medium"
                  value={years === 0 ? '' : years}
                  onChange={(e) => setYears(Number(e.target.value))}
                />
              </div>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
              <div>
                <label className="block text-xs font-semibold text-slate-700 mb-1">URL Perfil LinkedIn</label>
                <input
                  type="url"
                  placeholder="https://linkedin.com/in/..."
                  className="w-full p-2.5 border border-slate-300 rounded-lg text-sm bg-white text-slate-900 placeholder-slate-400 focus:ring-2 focus:ring-blue-500 outline-none transition-all font-medium"
                  value={linkedin}
                  onChange={(e) => setLinkedin(e.target.value)}
                />
              </div>
              <div>
                <label className="block text-xs font-semibold text-slate-700 mb-1">URL Currículum Vitae (PDF)</label>
                <input
                  type="url"
                  placeholder="https://..."
                  className="w-full p-2.5 border border-slate-300 rounded-lg text-sm bg-white text-slate-900 placeholder-slate-400 focus:ring-2 focus:ring-blue-500 outline-none transition-all font-medium"
                  value={cvUrl}
                  onChange={(e) => setCvUrl(e.target.value)}
                />
              </div>
            </div>
          </div>

          <div className="flex gap-4 justify-end pt-2">
            <Link
              href="/"
              className="px-5 py-2.5 rounded-lg text-sm font-semibold text-slate-600 hover:bg-slate-100 border border-slate-200 transition-all text-center"
            >
              Cancelar
            </Link>
            <button
              type="submit"
              disabled={loading}
              className="px-6 py-2.5 bg-blue-600 hover:bg-blue-700 text-white font-semibold text-sm rounded-lg shadow-sm transition-all disabled:opacity-50 flex items-center justify-center gap-2"
            >
              {loading ? (
                <>
                  <div className="animate-spin rounded-full h-4 w-4 border-b-2 border-white"></div>
                  Procesando...
                </>
              ) : (
                'Guardar Candidato'
              )}
            </button>
          </div>

        </form>
      </div>
    </main>
  );
}

// /components/CandidateDashboard.tsx
'use client';

import { useEffect, useState } from 'react';
import { useRouter, useSearchParams } from 'next/navigation';
import Link from 'next/link';
import { talentApi } from '@/services/api';

type DashboardCandidate = {
  id: string;
  full_name: string;
  email: string;
  position?: string;
  experience_years?: number;
  status?: string;
  step?: string;
  stage?: string;
};

const normalizeCandidate = (candidate: any): DashboardCandidate | null => {
  if (!candidate || typeof candidate !== 'object') return null;

  const fullName = String(candidate.full_name || '').trim();
  if (!fullName || fullName.includes('#')) return null;

  return {
    ...candidate,
    id: String(candidate.id),
    full_name: fullName,
    step: String(candidate.step || candidate.stage || '').trim() || 'initial_screen',
    experience_years: Number(candidate.experience_years || candidate.years_of_experience || 0),
  };
};

const mergeUniqueById = (items: DashboardCandidate[]): DashboardCandidate[] => {
  const map = new Map<string, DashboardCandidate>();
  for (const item of items) {
    if (item?.id && !map.has(item.id)) {
      map.set(item.id, item);
    }
  }
  return Array.from(map.values());
};

// Datos de semilla locales para que la interfaz nunca se vea vacía en la primera carga
const BACKUP_CANDIDATES = [
  {
    id: "mock-1",
    full_name: "Dr. Michael Smith",
    email: "m.smith@healthcore.com",
    position: "Cardiólogo Clínico",
    experience_years: 8,
    status: "in_progress",
    step: "clinical_assessment"
  },
  {
    id: "mock-2",
    full_name: "Enf. Sandra Ortega",
    email: "sandra.o@healthcore.com",
    position: "Enfermera Instrumentista",
    experience_years: 4,
    status: "received",
    step: "initial_screen"
  }
];

export default function CandidateDashboard() {
  const router = useRouter();
  const searchParams = useSearchParams();

  // Estados locales para los datos de la API
  const [candidates, setCandidates] = useState<DashboardCandidate[]>([]);
  const [loading, setLoading] = useState<boolean>(true);
  const [error, setError] = useState<string | null>(null);

  // Filtros de la URL de Next.js
  const currentStatus = searchParams.get('status') || 'all';
  const currentStep = searchParams.get('step') || 'all';
  const searchQuery = searchParams.get('search') || '';

  // Función de carga de datos pura y limpia
  const loadCandidates = async () => {
    try {
      setLoading(true);
      setError(null);

      const responseData = await talentApi.getRecords();
      console.log("Datos frescos recuperados del servidor:", responseData);

      let serverRecords: any[] = [];
      if (Array.isArray(responseData)) {
        serverRecords = responseData;
      } else if (responseData && typeof responseData === 'object') {
        const payload = responseData as Record<string, unknown>;
        const records = payload.records;
        const data = payload.data;
        serverRecords = Array.isArray(records)
          ? records
          : Array.isArray(data)
            ? data
            : [];
      }

      const validServerRecords = serverRecords
        .map(normalizeCandidate)
        .filter((candidate): candidate is DashboardCandidate => candidate !== null);

      const latestCandidateRaw = typeof window !== 'undefined' ? window.sessionStorage.getItem('latestCandidate') : null;
      let latestCandidate: DashboardCandidate | null = null;
      if (latestCandidateRaw) {
        try {
          latestCandidate = normalizeCandidate(JSON.parse(latestCandidateRaw));
        } catch {
          latestCandidate = null;
        }
      }

      // ESTRATEGIA DE HIDRATACIÓN PERFECCIONADA:
      // Combinamos siempre los datos reales del servidor (los nuevos que agregas) 
      // junto con los de respaldo para mantener el Dashboard interactivo.
      const normalizedBackup = BACKUP_CANDIDATES
        .map(normalizeCandidate)
        .filter((candidate): candidate is DashboardCandidate => candidate !== null);

      setCandidates(mergeUniqueById([
        ...(latestCandidate ? [latestCandidate] : []),
        ...validServerRecords,
        ...normalizedBackup,
      ]));

    } catch (err: any) {
      console.error("Error al conectar con la API en Dashboard:", err);
      setCandidates(BACKUP_CANDIDATES);
      setError("Modo Demo Activo: Cargando datos de contingencia local.");
    } finally {
      setLoading(false);
    }
  };

  // Forzar recarga cada vez que cambien los parámetros de búsqueda o filtros
  useEffect(() => {
    loadCandidates();
  }, [searchParams]);

  // Manejo de actualización manual (Botón Sincronizar)
  const handleManualRefresh = () => {
    router.refresh();
    loadCandidates();
  };

  // Actualizar parámetros en la barra de direcciones de Next.js
  const updateFilters = (key: string, value: string) => {
    const params = new URLSearchParams(searchParams.toString());
    if (value && value !== 'all') {
      params.set(key, value);
    } else {
      params.delete(key);
    }
    router.push(`/?${params.toString()}`);
  };

  // Lógica de filtrado en cliente tolerante a nulos
  const filteredCandidates = candidates.filter(candidate => {
    if (!candidate) return false;

    // Filtro por Estado (received, in_progress, discarded)
    const candidateStatus = candidate.status ? String(candidate.status).toLowerCase().trim() : 'received';
    const matchStatus = currentStatus === 'all' || candidateStatus === currentStatus.toLowerCase().trim();

    // Filtro por Etapa Clínica
    const candidateStep = candidate.step ? String(candidate.step).toLowerCase().trim() : 'initial_screen';
    const matchStep = currentStep === 'all' || candidateStep === currentStep.toLowerCase().trim();

    // Búsqueda selectiva por Texto
    const fullName = String(candidate.full_name || '').toLowerCase().trim();
    const email = String(candidate.email || '').toLowerCase().trim();

    const search = searchQuery.toLowerCase().trim();
    const matchSearch = search === '' || fullName.includes(search) || email.includes(search);

    return matchStatus && matchStep && matchSearch;
  });

  return (
    <div className="space-y-6">
      {/* SECCIÓN DE CONTROLES Y FILTROS */}
      <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200 space-y-4">
        <div className="flex flex-col md:flex-row gap-4 justify-between items-center">
          <div className="w-full md:w-1/3 relative">
            <input
              type="text"
              placeholder="Buscar por nombre o email..."
              className="w-full pl-4 pr-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none text-sm text-slate-900 font-medium"
              value={searchQuery}
              onChange={(e) => updateFilters('search', e.target.value)}
            />
          </div>

          <div className="w-full md:w-auto flex flex-wrap gap-3 items-center">
            <button 
              onClick={handleManualRefresh}
              className="p-2 text-slate-700 hover:text-blue-600 border border-slate-300 rounded-lg bg-white text-sm font-semibold transition-colors mt-5 flex items-center gap-1 shadow-sm"
            >
              🔄 Sincronizar
            </button>

            <div>
              <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1">Estado</label>
              <select
                className="p-2 border border-slate-300 rounded-lg text-sm bg-white focus:ring-2 focus:ring-blue-500 outline-none font-medium text-slate-800"
                value={currentStatus}
                onChange={(e) => updateFilters('status', e.target.value)}
              >
                <option value="all">Todos los Estados</option>
                <option value="received">Recibido (received)</option>
                <option value="in_progress">En Progreso (in_progress)</option>
                <option value="discarded">Descartado (discarded)</option>
              </select>
            </div>

            <div>
              <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-1">Etapa Clínica</label>
              <select
                className="p-2 border border-slate-300 rounded-lg text-sm bg-white focus:ring-2 focus:ring-blue-500 outline-none font-medium text-slate-800"
                value={currentStep}
                onChange={(e) => updateFilters('step', e.target.value)}
              >
                <option value="all">Todas las Etapas</option>
                <option value="initial_screen">Filtro Inicial</option>
                <option value="clinical_assessment">Evaluación Clínica</option>
                <option value="manager_interview">Entrevista Dirección</option>
                <option value="background_check">Verificación (Compliance)</option>
                <option value="final_decision">Decisión Final</option>
              </select>
            </div>

            <Link
              href="/candidates/new"
              className="mt-5 px-4 py-2 bg-blue-600 hover:bg-blue-700 text-white font-semibold text-sm rounded-lg transition-colors shadow-sm"
            >
              + Nuevo Candidato
            </Link>
          </div>
        </div>
      </div>

      {/* MANEJO DE AVISOS ASÍNCRONOS */}
      {loading && (
        <div className="text-center py-12 bg-white rounded-xl border border-slate-200">
          <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600 mx-auto mb-3"></div>
          <p className="text-slate-500 text-sm">Actualizando base de datos en tiempo real...</p>
        </div>
      )}

      {error && !loading && (
        <div className="bg-amber-50 border border-amber-200 text-amber-800 p-4 rounded-xl text-sm">
          ⚠️ {error}
        </div>
      )}

      {/* TABLA PRINCIPAL DE EXTRACCIÓN */}
      {!loading && (
        <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-slate-50 border-b border-slate-200 text-xs font-semibold text-slate-500 uppercase tracking-wider">
                <th className="p-4">Candidato</th>
                <th className="p-4">Posición</th>
                <th className="p-4">Años Exp.</th>
                <th className="p-4">Estado</th>
                <th className="p-4">Etapa</th>
                <th className="p-4 text-right">Acciones</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100 text-sm text-slate-700">
              {filteredCandidates.length === 0 ? (
                <tr>
                  <td colSpan={6} className="text-center py-12 text-slate-400 italic">
                    No se encontraron expedientes clínicos con los filtros seleccionados.
                  </td>
                </tr>
              ) : (
                filteredCandidates.map((candidate) => (
                  <tr key={candidate.id} className="hover:bg-slate-50/70 transition-colors">
                    <td className="p-4">
                      <div className="font-semibold text-slate-900">{candidate.full_name}</div>
                      <div className="text-xs text-slate-400">{candidate.email}</div>
                    </td>
                    <td className="p-4 font-medium text-slate-600">{candidate.position || 'No especificada'}</td>
                    <td className="p-4">{candidate.experience_years || 0} años</td>
                    <td className="p-4">
                      <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium ${
                        candidate.status === 'in_progress' ? 'bg-amber-50 text-amber-700 border border-amber-200' :
                        candidate.status === 'discarded' ? 'bg-red-50 text-red-700 border border-red-200' :
                        'bg-blue-50 text-blue-700 border border-blue-200'
                      }`}>
                        {candidate.status || 'received'}
                      </span>
                    </td>
                    <td className="p-4 text-slate-500">
                      {candidate.step === 'initial_screen' && 'Filtro Inicial'}
                      {candidate.step === 'clinical_assessment' && 'Evaluación Clínica'}
                      {candidate.step === 'manager_interview' && 'Entrevista Dirección'}
                      {candidate.step === 'background_check' && 'Verificación'}
                      {candidate.step === 'final_decision' && 'Decisión Final'}
                      {!candidate.step && 'Sin asignar'}
                    </td>
                    <td className="p-4 text-right">
                      <Link
                        href={`/candidates/${candidate.id}`}
                        className="text-blue-600 hover:text-blue-800 font-semibold hover:underline"
                      >
                        Revisar perfil &rarr;
                      </Link>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}

// /components/CandidateDetail.tsx
'use client';

import { useEffect, useState } from 'react';
import Link from 'next/link';
import { talentApi } from '@/services/api';
import { Candidate, CandidateNote, ApplicationStatus, ApplicationStep } from '@/types/tracker';

const STATUS_OPTIONS: Array<{ value: ApplicationStatus; label: string }> = [
  { value: 'received', label: 'Recibido' },
  { value: 'in_progress', label: 'En Progreso' },
  { value: 'selected', label: 'Seleccionado' },
  { value: 'discarded', label: 'Descartado' },
];

const STAGE_OPTIONS: Array<{ value: ApplicationStep; label: string }> = [
  { value: 'pending', label: 'Pendiente' },
  { value: 'review', label: 'Revisión' },
  { value: 'personal_interview', label: 'Entrevista Personal' },
  { value: 'technical_interview', label: 'Entrevista Técnica' },
  { value: 'offer_presented', label: 'Oferta Presentada' },
];

export default function CandidateDetail({ candidateId }: { candidateId: string }) {
  const [candidate, setCandidate] = useState<Candidate | null>(null);
  const [notes, setNotes] = useState<CandidateNote[]>([]);

  const [loading, setLoading] = useState<boolean>(true);
  const [error, setError] = useState<string | null>(null);
  const [actionLoading, setActionLoading] = useState<boolean>(false);

  const [newNote, setNewNote] = useState<string>('');
  const [noteSubmitting, setNoteSubmitting] = useState<boolean>(false);

  useEffect(() => {
    const fetchDetailData = async () => {
      try {
        setLoading(true);
        setError(null);

        const [candidateData, notesData] = await Promise.all([
          talentApi.getRecordById(candidateId).catch(err => { throw err; }),
          talentApi.getNotes(candidateId).catch(() => [])
        ]);

        setCandidate({
          ...candidateData,
          status: (candidateData.status || 'received') as ApplicationStatus,
          stage: (candidateData.stage || candidateData.step || 'pending') as ApplicationStep,
          step: (candidateData.step || candidateData.stage || 'pending') as ApplicationStep,
        });
        setNotes(Array.isArray(notesData) ? notesData : []);

      } catch (err: any) {
        setError(err.message || 'Error al obtener el expediente del candidato.');
      } finally {
        setLoading(false);
      }
    };

    fetchDetailData();
  }, [candidateId]);

  // 2. Actualización de Estado (Estrategia Dual para Diagnóstico)
  const handleUpdatePipeline = async (type: 'status' | 'stage', value: string) => {
    if (!candidate) return;

    try {
      setActionLoading(true);

      // Intentamos primero la forma más estándar posible para un PATCH clásico: enviar SOLO la llave que cambió.
      // Si la API arroja 422, nuestro catch atrapará la respuesta exacta del servidor.
      const minimalPayload = {
        [type]: value
      };

      const updatedCandidate = await talentApi.patchRecordStatus(candidateId, minimalPayload);
      setCandidate({
        ...updatedCandidate,
        status: (updatedCandidate.status || candidate.status || 'received') as ApplicationStatus,
        stage: (updatedCandidate.stage || updatedCandidate.step || candidate.stage || candidate.step || 'pending') as ApplicationStep,
        step: (updatedCandidate.step || updatedCandidate.stage || candidate.step || candidate.stage || 'pending') as ApplicationStep,
      });
    } catch (err: any) {
      if (err.message.startsWith('API_422_DETAIL:')) {
        // Extraemos y formateamos el JSON interno para que sea legible en el navegador
        const rawDetail = err.message.replace('API_422_DETAIL: ', '');
        alert(`La API rechazó el cambio (Error 422).\n\nRespuesta exacta del servidor:\n${rawDetail}`);
      } else {
        alert(`Error al actualizar el expediente: ${err.message}`);
      }
    } finally {
      setActionLoading(false);
    }
  };

  const handleAddNote = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newNote.trim()) return;

    try {
      setNoteSubmitting(true);
      const addedNote = await talentApi.addNote(candidateId, newNote.trim());
      setNotes(prev => [...prev, addedNote]);
      setNewNote(''); 
    } catch (err: any) {
      alert(`Error al guardar la nota: ${err.message}`);
    } finally {
      setNoteSubmitting(false);
    }
  };

  const handleDeleteNote = async (noteId: string | number) => {
    const confirmDelete = window.confirm("¿Seguro que deseas eliminar esta nota del expediente?");
    if (!confirmDelete) return;

    try {
      await talentApi.deleteNote(candidateId, noteId);
      setNotes(prev => prev.filter(note => String(note.id) !== String(noteId)));
    } catch (err: any) {
      alert(`Error al eliminar la nota: ${err.message}`);
    }
  };

  if (loading) {
    return (
      <div className="flex flex-col items-center justify-center h-64 bg-white rounded-xl border border-slate-200">
        <div className="animate-spin rounded-full h-10 w-10 border-b-2 border-blue-600 mb-4"></div>
        <p className="text-slate-500">Recuperando expediente médico/administrativo...</p>
      </div>
    );
  }

  if (error || !candidate) {
    return (
      <div className="bg-red-50 border-l-4 border-red-500 p-6 rounded-r-xl shadow-sm">
        <h3 className="text-red-800 font-bold text-lg mb-2">Expediente no accesible</h3>
        <p className="text-red-700">{error || 'Candidato no encontrado'}</p>
        <Link href="/" className="inline-block mt-4 text-blue-600 hover:underline">
          &larr; Volver
        </Link>
      </div>
    );
  }

  const safeNotes = Array.isArray(notes) ? notes : [];

