                  {candidate.cv_url && !candidate.cv_url.includes('no-proporcionado.com') && (
                    <li>
                      <a href={candidate.cv_url} target="_blank" rel="noreferrer" className="text-blue-600 hover:underline">
                        Ver CV Documentado &#8599;
                      </a>
                    </li>
                  )}
